/**
 * Packed Knot tests -- each test mirrors a Lean 4 theorem
 * from FoldedKnotBitPacking.lean (20 theorems, zero sorry).
 */

import { describe, expect, it } from '@a0n/gnosis/test';
import {
  FORK,
  FOLD,
  RACE,
  VENT,
  dnaToKnot,
  knotToDna,
  coil,
  release,
  getCrossing,
  setCrossing,
  composeKnots,
  hammingDistance,
  toBytes,
  fromBytes,
  edgeTypeToCrossing,
  crossingName,
  type PackedKnot,
  type CrossingOp,
  sliceKnot,
  crossover,
  crossover2,
  mutate,
  evolveGeneration,
  type FitnessFunction,
} from './packed-knot';
import type { GraphAST, ASTEdge } from '../betty/compiler';

function makeEdge(
  type: string,
  sourceIds: string[],
  targetIds: string[]
): ASTEdge {
  return { type, sourceIds, targetIds, properties: {} };
}

function makeAST(edges: ASTEdge[]): GraphAST {
  const nodes = new Map<
    string,
    { id: string; labels: string[]; properties: Record<string, string> }
  >();
  for (const edge of edges) {
    for (const id of [...edge.sourceIds, ...edge.targetIds]) {
      if (!nodes.has(id)) {
        nodes.set(id, { id, labels: [id], properties: {} });
      }
    }
  }
  return { nodes, edges };
}

function packFromOps(ops: CrossingOp[]): PackedKnot {
  const byteCount = Math.ceil(ops.length / 4);
  const crossings = new Uint8Array(byteCount);
  for (let i = 0; i < ops.length; i++) {
    crossings[i >> 2] |= ops[i] << (6 - 2 * (i & 3));
  }
  return {
    crossingCount: ops.length,
    crossings,
    nodeIds: ops.map((_, i) => `n${i}`),
  };
}

// ─── pack_unpack_roundtrip ───────────────────────────────────────────

describe('pack_unpack_roundtrip', () => {
  it('coil then release = original operations', () => {
    const ast = makeAST([
      makeEdge('FORK', ['a'], ['b']),
      makeEdge('RACE', ['b'], ['c']),
      makeEdge('FOLD', ['c'], ['d']),
      makeEdge('VENT', ['d'], ['e']),
    ]);

    const knot = coil(ast);
    const ops: CrossingOp[] = [];
    for (const crossing of release(knot)) {
      ops.push(crossing.op);
    }

    expect(ops).toEqual([FORK, RACE, FOLD, VENT]);
  });

  it('empty AST = empty knot', () => {
    const knot = coil({ nodes: new Map(), edges: [] });
    expect(knot.crossingCount).toBe(0);
    expect(knot.crossings.length).toBe(0);
  });
});

// ─── random_access ───────────────────────────────────────────────────

describe('random_access', () => {
  it('getCrossing matches sequential read', () => {
    const ops: CrossingOp[] = [FORK, RACE, FOLD, VENT, FORK, FOLD];
    const knot = packFromOps(ops);

    for (let i = 0; i < ops.length; i++) {
      expect(getCrossing(knot, i)).toBe(ops[i]);
    }
  });

  it('reads across byte boundaries', () => {
    // 5 crossings = 2 bytes, last crossing at position 4 spans byte boundary
    const ops: CrossingOp[] = [FORK, RACE, FOLD, VENT, RACE];
    const knot = packFromOps(ops);
    expect(getCrossing(knot, 4)).toBe(RACE);
  });
});

// ─── size_is_crossing_count ──────────────────────────────────────────

describe('size_is_crossing_count', () => {
  it('structure = size = data', () => {
    const ops: CrossingOp[] = [FORK, RACE, FOLD, VENT, FORK, RACE, FOLD];
    const knot = packFromOps(ops);
    expect(knot.crossingCount).toBe(ops.length);
  });
});

// ─── zero_overhead ───────────────────────────────────────────────────

describe('zero_overhead', () => {
  it('storage = content, no wrapper beyond header', () => {
    const ops: CrossingOp[] = [FORK, RACE, FOLD, VENT];
    const knot = packFromOps(ops);
    // 4 crossings = 1 byte of crossing data
    expect(knot.crossings.length).toBe(1);
    expect(Math.ceil(knot.crossingCount / 4)).toBe(knot.crossings.length);
  });
});

// ─── compose_size + compose_assoc ────────────────────────────────────

describe('compose', () => {
  it('concatenation preserves total bits', () => {
    const a = packFromOps([FORK, RACE]);
    const b = packFromOps([FOLD, VENT]);
    const composed = composeKnots(a, b);
    expect(composed.crossingCount).toBe(a.crossingCount + b.crossingCount);
  });

  it('composition is associative', () => {
    const a = packFromOps([FORK]);
    const b = packFromOps([RACE]);
    const c = packFromOps([FOLD]);

    const ab_c = composeKnots(composeKnots(a, b), c);
    const a_bc = composeKnots(a, composeKnots(b, c));

    expect(ab_c.crossingCount).toBe(a_bc.crossingCount);
    for (let i = 0; i < ab_c.crossingCount; i++) {
      expect(getCrossing(ab_c, i)).toBe(getCrossing(a_bc, i));
    }
  });

  it('left component preserved', () => {
    const a = packFromOps([FORK, RACE, FOLD]);
    const b = packFromOps([VENT, FORK]);
    const composed = composeKnots(a, b);

    for (let i = 0; i < a.crossingCount; i++) {
      expect(getCrossing(composed, i)).toBe(getCrossing(a, i));
    }
  });
});

// ─── empty_knot ──────────────────────────────────────────────────────

describe('empty_knot', () => {
  it('empty knot = empty data = void', () => {
    const empty = packFromOps([]);
    expect(empty.crossingCount).toBe(0);
  });

  it('void composes as identity', () => {
    const empty = packFromOps([]);
    const k = packFromOps([FORK, RACE]);
    const left = composeKnots(empty, k);
    const right = composeKnots(k, empty);

    expect(left.crossingCount).toBe(k.crossingCount);
    expect(right.crossingCount).toBe(k.crossingCount);
    for (let i = 0; i < k.crossingCount; i++) {
      expect(getCrossing(left, i)).toBe(getCrossing(k, i));
      expect(getCrossing(right, i)).toBe(getCrossing(k, i));
    }
  });
});

// ─── push_pop (setCrossing / getCrossing roundtrip) ──────────────────

describe('push_pop', () => {
  it('write then read = round-trip', () => {
    const knot = packFromOps([VENT, VENT, VENT, VENT]);
    setCrossing(knot, 2, FORK);
    expect(getCrossing(knot, 2)).toBe(FORK);
    // Other crossings unchanged
    expect(getCrossing(knot, 0)).toBe(VENT);
    expect(getCrossing(knot, 1)).toBe(VENT);
    expect(getCrossing(knot, 3)).toBe(VENT);
  });
});

// ─── hamming ─────────────────────────────────────────────────────────

describe('hamming', () => {
  it('self_zero_dist: zero distance from itself', () => {
    const k = packFromOps([FORK, RACE, FOLD, VENT]);
    expect(hammingDistance(k, k)).toBe(0);
  });

  it('dist_symmetric: twin divergence is symmetric', () => {
    const a = packFromOps([FORK, RACE, FOLD, VENT]);
    const b = packFromOps([VENT, RACE, FORK, FOLD]);
    expect(hammingDistance(a, b)).toBe(hammingDistance(b, a));
  });

  it('hamming_weight_le_size: distance bounded by size', () => {
    const a = packFromOps([FORK, FORK, FORK, FORK]);
    const b = packFromOps([VENT, VENT, VENT, VENT]);
    expect(hammingDistance(a, b)).toBeLessThanOrEqual(a.crossingCount);
  });
});

// ─── sequence_matters (anti-theorem) ─────────────────────────────────

describe('sequence_matters', () => {
  it('order matters -- consciousness is temporal', () => {
    const a = packFromOps([FORK, FOLD]);
    const b = packFromOps([FOLD, FORK]);
    expect(getCrossing(a, 0)).not.toBe(getCrossing(b, 0));
  });
});

// ─── serialization roundtrip ─────────────────────────────────────────

describe('serialization', () => {
  it('toBytes/fromBytes round-trips', () => {
    const ops: CrossingOp[] = [FORK, RACE, FOLD, VENT, FORK, RACE];
    const original = packFromOps(ops);
    const bytes = toBytes(original);
    const restored = fromBytes(bytes);

    expect(restored.crossingCount).toBe(original.crossingCount);
    for (let i = 0; i < original.crossingCount; i++) {
      expect(getCrossing(restored, i)).toBe(getCrossing(original, i));
    }
  });

  it('preserves node IDs', () => {
    const knot: PackedKnot = {
      crossingCount: 3,
      crossings: new Uint8Array([0b11_10_01_00]),
      nodeIds: ['alpha', 'beta', 'gamma'],
    };
    const restored = fromBytes(toBytes(knot));
    expect(restored.nodeIds).toEqual(['alpha', 'beta', 'gamma']);
  });

  it('RLE Compression round-trips (Vacuum Gap)', () => {
    // 100 identical VENT ops should trigger RLE
    const ops: CrossingOp[] = Array.from({ length: 100 }, () => VENT);
    const knot = packFromOps(ops);
    const bytes = toBytes(knot);
    
    // Header (8) + CrossingCount (1) + RLELen (1) + RLEData (2) + UniqueIdCount (1) + UniqueId (2) + Indices (100)
    // Wait, indices are still there. String table is holographic but crossings are RLE.
    // The crossing data itself should be small.
    const restored = fromBytes(bytes);
    expect(restored.crossingCount).toBe(100);
    for (let i = 0; i < 100; i++) {
        expect(getCrossing(restored, i)).toBe(VENT);
    }
  });

  it('Large Knot Support (>64KB payload) with CRC-32', () => {
    // Create a knot that exceeds 64KB inner payload
    // Each index size is 2 bytes (or 1 if < 256), so 40,000 crossings = ~40-80KB
    const crossingCount = 40000;
    const ops: CrossingOp[] = Array.from({ length: crossingCount }, (_, i) => (i % 4) as CrossingOp);
    const knot = packFromOps(ops);
    
    const bytes = toBytes(knot);
    // Should have FLAG_LARGE (0x80) in header[3]
    expect(bytes[3] & 0x80).toBe(0x80);
    
    const restored = fromBytes(bytes);
    expect(restored.crossingCount).toBe(crossingCount);
    expect(getCrossing(restored, 39999)).toBe(ops[39999]);
  });
});

// ─── edgeTypeToCrossing ──────────────────────────────────────────────

describe('edgeTypeToCrossing', () => {
  it('maps all synonyms correctly', () => {
    expect(edgeTypeToCrossing('FORK')).toBe(FORK);
    expect(edgeTypeToCrossing('EVOLVE')).toBe(FORK);
    expect(edgeTypeToCrossing('SUPERPOSE')).toBe(FORK);
    expect(edgeTypeToCrossing('RACE')).toBe(RACE);
    expect(edgeTypeToCrossing('FOLD')).toBe(FOLD);
    expect(edgeTypeToCrossing('COLLAPSE')).toBe(FOLD);
    expect(edgeTypeToCrossing('VENT')).toBe(VENT);
    expect(edgeTypeToCrossing('TUNNEL')).toBe(VENT);
  });

  it('crossingName round-trips', () => {
    expect(crossingName(FORK)).toBe('FORK');
    expect(crossingName(RACE)).toBe('RACE');
    expect(crossingName(FOLD)).toBe('FOLD');
    expect(crossingName(VENT)).toBe('VENT');
  });
});

// ─── Reidemeister optimizations ──────────────────────────────────────

describe('reidemeister', () => {
  it('R1: eliminates self-loops', () => {
    const ast = makeAST([
      makeEdge('FORK', ['a'], ['a']), // self-loop -- should be eliminated
      makeEdge('RACE', ['b'], ['c']),
    ]);
    const knot = coil(ast);
    expect(knot.crossingCount).toBe(1);
    expect(getCrossing(knot, 0)).toBe(RACE);
  });

  it('R2: cancels adjacent FORK-FOLD pairs', () => {
    const ast = makeAST([
      makeEdge('FORK', ['a'], ['b', 'c']),
      makeEdge('FOLD', ['b', 'c'], ['d']),
      makeEdge('RACE', ['d'], ['e']),
    ]);
    const knot = coil(ast);
    // FORK-FOLD pair cancelled, only RACE remains
    expect(knot.crossingCount).toBe(1);
    expect(getCrossing(knot, 0)).toBe(RACE);
  });
});

// ─── Self-modification ──────────────────────────────────────────────

describe('self-modification', () => {
  it('vent feeds back, crossing stream grows', () => {
    const knot = packFromOps([VENT, FOLD]);
    const gen = release(knot);

    // First crossing: VENT
    const first = gen.next();
    expect(first.value?.op).toBe(VENT);

    // Feed back FORK and RACE as new crossings
    const second = gen.next([FORK, RACE]);
    expect(second.value?.op).toBe(FOLD);

    // The spliced crossings appear after
    const third = gen.next();
    expect(third.value?.op).toBe(FORK);

    const fourth = gen.next();
    expect(fourth.value?.op).toBe(RACE);

    // Done
    expect(gen.next().done).toBe(true);
  });
});

// ─── wrapper_costs ───────────────────────────────────────────────────

describe('wrapper_costs', () => {
  it('non-self-encoding always costs more', () => {
    const ops: CrossingOp[] = [FORK, RACE, FOLD, VENT];
    const knot = packFromOps(ops);
    const knotBytes = Math.ceil(knot.crossingCount / 4);
    const jsonBytes = JSON.stringify(ops.map(crossingName)).length;
    expect(knotBytes).toBeLessThan(jsonBytes);
  });
});

// ─── GENETIC EVOLUTION ───────────────────────────────────────────────

describe('sliceKnot', () => {
  it('extracts a contiguous sub-knot', () => {
    const knot = packFromOps([FORK, RACE, FOLD, VENT, FORK, RACE]);
    const slice = sliceKnot(knot, 1, 4);
    expect(slice.crossingCount).toBe(3);
    expect(getCrossing(slice, 0)).toBe(RACE);
    expect(getCrossing(slice, 1)).toBe(FOLD);
    expect(getCrossing(slice, 2)).toBe(VENT);
  });

  it('slice preserves node IDs', () => {
    const knot = packFromOps([FORK, RACE, FOLD, VENT]);
    const slice = sliceKnot(knot, 1, 3);
    expect(slice.nodeIds).toEqual(knot.nodeIds.slice(1, 3));
  });

  it('empty slice returns empty knot', () => {
    const knot = packFromOps([FORK, RACE]);
    const slice = sliceKnot(knot, 2, 2);
    expect(slice.crossingCount).toBe(0);
  });
});

describe('crossover', () => {
  it('single-point crossover combines two parents', () => {
    const a = packFromOps([FORK, FORK, FORK, FORK]);
    const b = packFromOps([VENT, VENT, VENT, VENT]);
    const child = crossover(a, b, 2);
    expect(child.crossingCount).toBe(4);
    expect(getCrossing(child, 0)).toBe(FORK); // from A
    expect(getCrossing(child, 1)).toBe(FORK); // from A
    expect(getCrossing(child, 2)).toBe(VENT); // from B
    expect(getCrossing(child, 3)).toBe(VENT); // from B
  });

  it('two-point crossover takes middle from B', () => {
    const a = packFromOps([FORK, FORK, FORK, FORK, FORK]);
    const b = packFromOps([VENT, VENT, VENT, VENT, VENT]);
    const child = crossover2(a, b, 1, 3);
    expect(getCrossing(child, 0)).toBe(FORK); // A head
    expect(getCrossing(child, 1)).toBe(VENT); // B mid
    expect(getCrossing(child, 2)).toBe(VENT); // B mid
    expect(getCrossing(child, 3)).toBe(FORK); // A tail
    expect(getCrossing(child, 4)).toBe(FORK); // A tail
  });
});

describe('mutate', () => {
  it('flips crossings in place', () => {
    const knot = packFromOps([VENT, VENT, VENT, VENT]);
    let callCount = 0;
    // Deterministic RNG: always mutate index 0 to FORK
    const rng = () => {
      callCount++;
      return callCount % 2 === 1 ? 0 : 0.75; // idx 0, op FORK
    };
    mutate(knot, 1, rng);
    expect(getCrossing(knot, 0)).toBe(FORK);
  });
});

describe('evolveGeneration', () => {
  it('produces a population of the same size', () => {
    const pop = [
      packFromOps([FORK, RACE, FOLD, VENT]),
      packFromOps([VENT, FOLD, RACE, FORK]),
      packFromOps([FORK, FORK, FOLD, FOLD]),
      packFromOps([RACE, RACE, RACE, RACE]),
    ];
    // Fitness: count FORKs (the +1 sliver -- mutation formalizes the exhaust)
    const fitness: FitnessFunction = (k) => {
      let score = 0;
      for (let i = 0; i < k.crossingCount; i++) {
        if (getCrossing(k, i) === FORK) score++;
      }
      return score;
    };
    const next = evolveGeneration(pop, fitness);
    expect(next.length).toBe(pop.length);
  });

  it('fittest individual improves over generations', () => {
    // Start with all VENTs
    const seed = packFromOps(Array.from({ length: 8 }, () => VENT));
    let pop = Array.from({ length: 10 }, () =>
      sliceKnot(seed, 0, seed.crossingCount)
    );

    // Fitness: count FORKs
    const fitness: FitnessFunction = (k) => {
      let score = 0;
      for (let i = 0; i < k.crossingCount; i++) {
        if (getCrossing(k, i) === FORK) score++;
      }
      return score;
    };

    // Evolve 50 generations with high mutation
    for (let gen = 0; gen < 50; gen++) {
      pop = evolveGeneration(pop, fitness, {
        mutationRate: 0.5,
        mutationCount: 2,
      });
    }

    // Best should have at least some FORKs now
    const bestScore = Math.max(...pop.map(fitness));
    expect(bestScore).toBeGreaterThan(0);
  });
});

describe('PackedKnot DNA Integration (V3)', () => {
  it('should support Gnosis DNA (Biochemical) round-trips', () => {
    const dna = 'ACGTACGT';
    const knot = dnaToKnot(dna);
    expect(knot.crossingCount).toBe(8);
    expect(knotToDna(knot)).toBe(dna);
  });

  it('should be case-insensitive to input DNA', () => {
    const dna = 'acgtACGT';
    const knot = dnaToKnot(dna);
    expect(knotToDna(knot)).toBe('ACGTACGT');
  });

  it('should ignore non-ACGT characters', () => {
    const dna = 'A C G T !';
    const knot = dnaToKnot(dna);
    expect(knotToDna(knot)).toBe('ACGT');
  });
});
